// Get filtered list of projects based on query
    function getFilteredProjects() {
      if (!searchQuery) return projects;

      return projects.filter(p => {
        const matchesProjName = p.name.toLowerCase().includes(searchQuery);
        const matchesProjPath = p.rootPath.toLowerCase().includes(searchQuery);
        const matchesSpaces = p.spaces.some(s => 
          s.name.toLowerCase().includes(searchQuery) || 
          s.path.toLowerCase().includes(searchQuery) ||
          (s.branch && s.branch.toLowerCase().includes(searchQuery))
        );

        return matchesProjName || matchesProjPath || matchesSpaces;
      });
    }

    // Main render router
    function renderAll() {
      renderSidebar();
      renderProjectList();
      renderRightPane();
    }

    // Render left sidebar header switcher
    function renderSidebar() {
      const activeProj = projects.find(p => p.id === activeProjectId);
      const activeSpace = activeProj ? activeProj.spaces.find(s => s.id === activeSpaceId) : null;

      const titleBtn = document.getElementById("sidebar-switch-btn");
      const titleSpan = document.getElementById("sb-title");
      const subtitleSpan = document.getElementById("sb-subtitle");
      const newBtn = document.getElementById("sb-new-btn");
      const wtBtn = document.getElementById("sb-wt-btn");

      if (activeProj && activeSpace) {
        titleSpan.textContent = activeProj.name;

        let subText = `空间：${activeSpace.name}`;
        if (activeSpace.branch) {
          subText += ` · 分支：${activeSpace.branch}`;
        }
        subtitleSpan.textContent = subText;
        subtitleSpan.title = activeSpace.path;

        newBtn.disabled = activeSpace.missing;
        wtBtn.disabled = false;

        newBtn.onclick = () => {
          if (activeSpace.missing) return;
          alert(`在工作空间 [${activeProj.name}] (${activeSpace.name}) 中创建新会话`);
        };
        wtBtn.onclick = () => {
          alert(`从当前路径 ${activeSpace.path} 创建新 WorkTree`);
        };
      } else {
        titleSpan.textContent = "选择项目空间";
        subtitleSpan.textContent = "尚未添加项目";
        subtitleSpan.title = "";

        newBtn.disabled = true;
        wtBtn.disabled = true;
      }

      // Wire switch button click
      titleBtn.onclick = (e) => {
        e.stopPropagation();
        openDialog();
      };
    }

    // Render Dialog left projects list
    function renderProjectList() {
      const listContainer = document.getElementById("project-list");
      listContainer.innerHTML = "";

      const filtered = getFilteredProjects();

      if (filtered.length === 0) {
        listContainer.innerHTML = `
          <div style="padding: 20px 12px; color: var(--text-dim); font-size: 11px; text-align: center;">
            无匹配的项目
          </div>
        `;
        return;
      }

      // Sort: pinned first, then alphabetical/original
      const sorted = [...filtered].sort((a, b) => {
        if (a.pinned && !b.pinned) return -1;
        if (!a.pinned && b.pinned) return 1;
        return a.name.localeCompare(b.name);
      });

      sorted.forEach(proj => {
        const card = document.createElement("button");
        card.className = `project-card ${proj.id === pendingProjectId ? "active" : ""}`;
        card.onclick = () => {
          pendingProjectId = proj.id;
          activeForm = null; // close form when selecting a project
          renderAll();
        };

        const starBadge = proj.pinned ? `<span class="badge badge-star">★</span>` : "";
        const spaceCount = proj.spaces.length;
        const countBadge = `<span class="badge badge-count">${spaceCount} space${spaceCount > 1 ? "s" : ""}</span>`;

        card.innerHTML = `
          <div class="card-line">
            ${starBadge}
            <span class="card-name" title="${proj.name}">${proj.name}</span>
            ${countBadge}
          </div>
          <div class="card-path" title="${proj.rootPath}">${proj.rootPath}</div>
        `;

        listContainer.appendChild(card);
      });
    }

    // Render Dialog right space pane / onboarding / forms
    function renderRightPane() {
      const pane = document.getElementById("space-pane-content");
      pane.innerHTML = "";

      // Active form state overrides regular project display
      if (activeForm === 'path') {
        renderPathForm(pane);
        updateActiveMiniButtons();
        return;
      }
      if (activeForm === 'git') {
        renderGitCloneForm(pane);
        updateActiveMiniButtons();
        return;
      }

      updateActiveMiniButtons();

      // Zero projects / onboarding state
      if (projects.length === 0) {
        renderOnboardingState(pane);
        return;
      }

      // Get pending selected project
      const proj = projects.find(p => p.id === pendingProjectId);
      if (!proj) {
        // Fallback: select first project if pending is invalid
        if (projects.length > 0) {
          pendingProjectId = projects[0].id;
          renderRightPane();
        }
        return;
      }

      // Header info for chosen project
      const header = document.createElement("div");
      header.className = "selected-project-header";

      const pinToggleText = proj.pinned ? "★ 取消置顶项目" : "☆ 置顶项目";

      header.innerHTML = `
        <div class="card-line" style="justify-content: space-between;">
