        <div class="card-path">${proj.rootPath}</div>
        <div class="header-hint">点击可用空间立即切换分支/目录。缺失路径保持禁用。</div>
      `;
      pane.appendChild(header);

      // Spaces list
      const list = document.createElement("div");
      list.className = "space-list";

      // Filter spaces based on search query if applicable
      let spacesToRender = proj.spaces;
      if (searchQuery) {
        spacesToRender = proj.spaces.filter(s => 
          s.name.toLowerCase().includes(searchQuery) || 
          s.path.toLowerCase().includes(searchQuery) ||
          (s.branch && s.branch.toLowerCase().includes(searchQuery))
        );
      }

      if (spacesToRender.length === 0) {
        list.innerHTML = `
          <div style="padding: 24px; text-align: center; color: var(--text-muted); font-size: 12px;">
            当前项目下无匹配空间
          </div>
        `;
        pane.appendChild(list);
        return;
      }

      spacesToRender.forEach(space => {
        const isCurrent = proj.id === activeProjectId && space.id === activeSpaceId;
        const card = document.createElement("button");
        card.className = `space-card ${isCurrent ? "active" : ""} ${space.missing ? "disabled" : ""}`;

        if (space.missing) {
          card.disabled = true;
          card.title = `路径不存在: ${space.path}`;
        } else {
          card.onclick = () => {
            selectSpace(proj.id, space.id);
          };
          card.title = `切换工作区到: ${space.path}`;
        }

        const isWt = space.kind === "worktree";
        const kindBadge = isWt 
          ? `<span class="badge badge-accent">WT</span>` 
          : `<span class="badge" style="background:var(--bg-panel);color:var(--text-muted)">Main</span>`;

        const checkMark = isCurrent ? `<span class="space-check">✓</span>` : "";
        const missingBadge = space.missing ? `<span class="badge badge-danger">路径缺失</span>` : "";

        let metaText = `分支: ${space.branch || 'unknown'}`;
        if (isWt && space.base) {
          metaText += ` · 基准: ${space.base}`;
        }
        metaText += ` · ${space.path}`;

        card.innerHTML = `
          <div class="space-title-row">
            ${checkMark}
            ${kindBadge}
            <span class="space-name">${space.name}</span>
            ${missingBadge}
          </div>
          <div class="space-meta" title="${metaText}">${metaText}</div>
        `;
        list.appendChild(card);
      });

      pane.appendChild(list);
    }

    function updateActiveMiniButtons() {
      const btnPath = document.getElementById("tb-btn-path");
      const btnGit = document.getElementById("tb-btn-git");

      if (btnPath && btnGit) {
        if (activeForm === 'path') {
          btnPath.classList.add("active");
          btnGit.classList.remove("active");
